class Solution:
    def minimumCost(self, s: str) -> int:
        n = len(s)
        res = float('inf')
        for target in ['0', '1']:
            cost = 0
            for i in range(n):
                if s[i] != target:
                    if i == 0:
                        cost += n
                    else:
                        cost += i + 1 if i < n - i else n - i
                    target = '1' if target == '0' else '0'
            res = min(res, cost)
        return res
